## 2. Creating Authentication Controller


### 2.1 File Structure Reorganization
- Move the `createUser()` function from `controllers/userController.js` to `controllers/authController.js`.

- Rename `createUser()` to `registerUser()` to follow the single responsibility principle.

### 2.2 User Registration Logic

```js
const registerUser = async (req, res) => {
  try {
    const { name, email, password, role } = req.body;
    const user = new User({
      name,
      email,
      password,
      role
    });
    const savedUser = await user.save();
    res.status(201).json(savedUser);
  } catch (error) {
    res.status(500).json({ message: "Error registering user" });
  }
};
module.exports = { registerUser };
```

---

## 3. Hashing Passwords

### 3.1 Why Hash Passwords?
- **Plaintext Passwords**: Storing passwords in plaintext is a serious security risk.
- **Hashed Passwords**: Hashing passwords ensures attackers cannot easily retrieve the original passwords even if the database is breached.

### 3.2 Installing `bcryptjs`
Run the following command to install the library:

```bash
npm install bcryptjs
```

### 3.3 Password Hashing in Registration Logic

```js
const bcrypt = require('bcryptjs');
const registerUser = async (req, res) => {
  try {
    const { name, email, password, role } = req.body;
    const hashedPassword = await bcrypt.hash(password, 10); // Salt round: 10
    const user = new User({
      name,
      email,
      password: hashedPassword,
      role
    });
    const savedUser = await user.save();
    res.status(201).json(savedUser);
  } catch (error) {
    res.status(500).json({ message: "Error registering user" });
  }
};
module.exports = { registerUser };
```

---

## 4. Adding Login Logic

### 4.1 Login Controller

```js
const bcrypt = require('bcryptjs');
const jwt = require("jsonwebtoken");

const loginUser = async (req, res) => {
  const { email, password } = req.body;
  const user = await User.findOne({ email });
  if (!user) {
    return res.status(400).send("Invalid credentials");
  }
  const isPasswordValid = await bcrypt.compare(password, user.password);
  if (!isPasswordValid) {
    return res.status(400).send("Invalid credentials");
  }
  const token = jwt.sign(
    { id: user._id, role: user.role },
    process.env.JWT_SECRET,
    { expiresIn: "1h" }
  );
  res.json({ token });
};
module.exports = { loginUser };
```

---

## 5. Protected Routes

### 5.1 Middleware for Token Verification
Create a new file `middlewares/authenticateToken.js`:

```js
const jwt = require("jsonwebtoken");

const authenticateToken = (req, res, next) => {
  const authHeader = req.header('Authorization');
  const token = authHeader?.split(' ')[1];
  if (!token) {
    return res.status(401).json({ message: "Access Denied: No Token Provided" });
  }
  jwt.verify(token, process.env.JWT_SECRET, (err, payload) => {
    if (err) {
      const msg = err.name === "TokenExpiredError" ? "Token Expired" : "Invalid Token";
      return res.status(err.name === "TokenExpiredError" ? 401 : 403).json({ message: msg });
    }
    req.user = payload;
    next();
  });
};
module.exports = { authenticateToken };
```

### 5.2 Securing Routes
Apply the middleware to protect routes:

```js
const express = require('express');
const router = express.Router();
const { getAllProducts } = require('../controllers/productController');
const { authenticateToken } = require('../middlewares/authenticateToken');

router.get('/', authenticateToken, getAllProducts);
module.exports = router;
```

