int longestSubarrayWithSumK(int arr[], int n, int k) {
    int max=0;
    for(int i=0;i<n;i++) {
        int sum=0;
        for(int j=i;j<n-1;j++) {
            sum += arr[j];
            int len = j-i+1;
            if(sum==k) {
                if(len>max) {
                    max=len;
                }
            }
        }
    }
    return max;
}

